import { existsSync } from "node:fs"
import { readFile, writeFile } from "node:fs/promises"
import { join, resolve } from "node:path"

import { writeLine } from "../../output.js"
import type { BuildEmitContext, BuildTarget } from "./index.js"

/**
 * Stable marker written as the first line of every Dawn-authored Dockerfile.
 * Its presence is how a rebuild tells its own prior output apart from a
 * user-authored/edited Dockerfile: Dawn-authored files are overwritten in
 * place (kept authoritative), user files are preserved.
 */
const DOCKERFILE_MARKER =
  "# Generated by dawn build (node target). Safe to edit; delete to regenerate."

/**
 * server.mjs lives at `<appRoot>/.dawn/build/server.mjs`, so the app root is
 * two directories up from the module's own location. Verified against
 * `buildDir = <appRoot>/.dawn/build`.
 */
const SERVER_ENTRY = `import { serveRuntime } from "@dawn-ai/cli"
import { fileURLToPath } from "node:url"
import { dirname, resolve } from "node:path"

// server.mjs lives at <appRoot>/.dawn/build/server.mjs → appRoot is two dirs up
const appRoot = resolve(dirname(fileURLToPath(import.meta.url)), "..", "..")

await serveRuntime({ appRoot })
`

/**
 * Hardened production Dockerfile.
 *
 * Circular-build decision: we deliberately do NOT `RUN npx dawn build` inside
 * the image. The host already ran `dawn build` to produce this Dockerfile (and
 * therefore a fresh `.dawn/build/`), and `COPY . .` brings that prebuilt output
 * — including `server.mjs` — into the image. Running the build again in-image
 * would (a) require the `dawn` CLI, which is typically a devDependency and thus
 * absent after `npm ci --omit=dev`, and (b) needlessly re-run typegen against
 * the copied context. Relying on the copied `.dawn/build/` is both simpler and
 * avoids any risk of recursive re-emission.
 */
const DOCKERFILE = `${DOCKERFILE_MARKER}
# syntax=docker/dockerfile:1
FROM node:22-slim
WORKDIR /app
ENV NODE_ENV=production HOST=0.0.0.0 PORT=8000
COPY package.json package-lock.json* pnpm-lock.yaml* ./
RUN npm ci --omit=dev || npm install --omit=dev
# IMPORTANT: the Docker build context MUST include \`.dawn/build\` (where
# server.mjs lives) — do NOT add \`.dawn/build\` to \`.dockerignore\`, or this
# COPY will omit the entry point and the container will fail to start.
COPY . .
# .dawn/build/ (incl. server.mjs) is copied from the host build context above;
# no in-image \`dawn build\` needed. See node.ts for the rationale.
RUN chown -R 1000:1000 /app/.dawn
USER 1000:1000
EXPOSE 8000
HEALTHCHECK --interval=30s --timeout=3s --start-period=20s \\
  CMD node -e "fetch('http://127.0.0.1:'+(process.env.PORT||8000)+'/healthz').then(r=>process.exit(r.ok?0:1)).catch(()=>process.exit(1))"
CMD ["node", ".dawn/build/server.mjs"]
`

/**
 * The Node/Docker deploy target. Emits a runnable `server.mjs` entry (which
 * boots {@link serveRuntime}) and a hardened `Dockerfile`.
 */
export const nodeTarget: BuildTarget = {
  name: "node",
  async emit({ appRoot, buildDir, io }: BuildEmitContext) {
    const artifacts: string[] = []

    const serverPath = join(buildDir, "server.mjs")
    await writeFile(serverPath, SERVER_ENTRY, "utf8")
    artifacts.push(serverPath)

    // server.mjs imports @dawn-ai/cli at runtime; `npm ci --omit=dev` strips it
    // if it's only a devDependency → the production container CrashLoops. Warn
    // (not a hard error — odd setups may resolve it another way) when it isn't a
    // runtime dependency.
    if (io) {
      await warnIfCliNotRuntimeDependency(appRoot, io)
    }

    // Dockerfile emission is idempotent and Dawn-authoritative:
    //   • no Dockerfile at appRoot            → write ours to appRoot
    //   • existing one contains our marker    → overwrite it in place at appRoot
    //   • existing one WITHOUT our marker     → user-authored; preserve it and
    //                                           emit ours into the build dir
    const appRootDockerfile = resolve(appRoot, "Dockerfile")
    let dockerfilePath = appRootDockerfile
    if (existsSync(appRootDockerfile)) {
      const existing = await readFile(appRootDockerfile, "utf8")
      if (!existing.includes(DOCKERFILE_MARKER)) {
        dockerfilePath = join(buildDir, "Dockerfile")
        if (io) {
          writeLine(
            io.stderr,
            `⚠ Preserved your existing ${appRootDockerfile} (not Dawn-authored); wrote the node target's Dockerfile to ${dockerfilePath} instead.`,
          )
        }
      }
    }
    await writeFile(dockerfilePath, DOCKERFILE, "utf8")
    artifacts.push(dockerfilePath)

    return { artifacts }
  },
}

/**
 * Warn when `@dawn-ai/cli` is absent from the app's `dependencies` (whether it
 * sits in `devDependencies` or is missing entirely). Best-effort: an
 * unreadable/malformed package.json is silently skipped rather than failing the
 * build.
 */
async function warnIfCliNotRuntimeDependency(
  appRoot: string,
  io: NonNullable<BuildEmitContext["io"]>,
): Promise<void> {
  const packageJsonPath = resolve(appRoot, "package.json")
  if (!existsSync(packageJsonPath)) {
    return
  }
  let dependencies: Record<string, unknown> = {}
  try {
    const parsed = JSON.parse(await readFile(packageJsonPath, "utf8")) as {
      dependencies?: Record<string, unknown>
    }
    if (parsed.dependencies && typeof parsed.dependencies === "object") {
      dependencies = parsed.dependencies
    }
  } catch {
    // Best-effort — skip the check on unreadable/malformed package.json.
    return
  }
  if (!Object.hasOwn(dependencies, "@dawn-ai/cli")) {
    writeLine(
      io.stderr,
      '⚠ The node target\'s server.mjs imports @dawn-ai/cli at runtime — add "@dawn-ai/cli" to "dependencies" (not devDependencies) or it will be stripped by `npm ci --omit=dev` in the production image.',
    )
  }
}
